#include <bits/stdc++.h>
using namespace std;
int n, b[1000005];
int main() {
	long long e = 1;
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> b[i];
	}
	sort(b + 1, b + n + 1);
	for (int i = 1; i <= n; i++) {
		if (b[i] >= e) {
			e++;
		}
	}
	cout << e - 1;
	return 0;
}
